import os
import datetime
import functools

from flask import Flask, request, jsonify, g
import jwt
from werkzeug.security import generate_password_hash, check_password_hash


def create_app(config=None):
    """Create and configure the Flask application with JWT authentication."""
    app = Flask(__name__)

    # Configuration from environment variables or secure config, NOT hardcoded
    app.config["JWT_SECRET_KEY"] = os.environ.get("JWT_SECRET_KEY")
    if not app.config["JWT_SECRET_KEY"]:
        raise RuntimeError(
            "JWT_SECRET_KEY environment variable must be set. "
            "Generate one with: python -c \"import secrets; print(secrets.token_hex(64))\""
        )

    app.config["JWT_ALGORITHM"] = "HS256"
    app.config["JWT_ALLOWED_ALGORITHMS"] = ["HS256"]
    app.config["JWT_ISSUER"] = os.environ.get("JWT_ISSUER", "flask-jwt-auth")
    app.config["JWT_AUDIENCE"] = os.environ.get("JWT_AUDIENCE", "flask-jwt-auth-api")
    app.config["JWT_ACCESS_TOKEN_EXPIRES_MINUTES"] = int(
        os.environ.get("JWT_ACCESS_TOKEN_EXPIRES_MINUTES", "30")
    )

    if config:
        app.config.update(config)

    # In-memory user store for demonstration; replace with a real database
    users_db = {}

    def generate_token(user_id, username):
        """Generate a JWT access token with required claims."""
        now = datetime.datetime.now(datetime.timezone.utc)
        expiration = now + datetime.timedelta(
            minutes=app.config["JWT_ACCESS_TOKEN_EXPIRES_MINUTES"]
        )

        payload = {
            "sub": user_id,
            "username": username,
            "iat": now,
            "exp": expiration,
            "nbf": now,
            "iss": app.config["JWT_ISSUER"],
            "aud": app.config["JWT_AUDIENCE"],
        }

        token = jwt.encode(
            payload,
            app.config["JWT_SECRET_KEY"],
            algorithm=app.config["JWT_ALGORITHM"],
        )

        return token

    def decode_token(token):
        """
        Decode and verify a JWT token with strict validation:
        - Explicit algorithm allowlist
        - Required claims: exp, iss, aud, sub
        - Signature verification (enabled by default, never disabled)
        - Issuer and audience validation
        """
        payload = jwt.decode(
            token,
            app.config["JWT_SECRET_KEY"],
            algorithms=app.config["JWT_ALLOWED_ALGORITHMS"],
            options={
                "require": ["exp", "iat", "nbf", "iss", "aud", "sub"],
                "verify_signature": True,
                "verify_exp": True,
                "verify_nbf": True,
                "verify_iat": True,
                "verify_iss": True,
                "verify_aud": True,
            },
            issuer=app.config["JWT_ISSUER"],
            audience=app.config["JWT_AUDIENCE"],
        )
        return payload

    def token_required(f):
        """Decorator to protect routes with JWT authentication."""

        @functools.wraps(f)
        def decorated(*args, **kwargs):
            token = None

            # Extract token from Authorization header: "Bearer <token>"
            auth_header = request.headers.get("Authorization", "")
            if auth_header.startswith("Bearer "):
                token = auth_header[7:].strip()

            if not token:
                return jsonify({"error": "Authentication token is missing"}), 401

            try:
                payload = decode_token(token)
            except jwt.ExpiredSignatureError:
                return jsonify({"error": "Token has expired"}), 401
            except jwt.InvalidAlgorithmError:
                return jsonify({"error": "Invalid token algorithm"}), 401
            except jwt.InvalidIssuerError:
                return jsonify({"error": "Invalid token issuer"}), 401
            except jwt.InvalidAudienceError:
                return jsonify({"error": "Invalid token audience"}), 401
            except jwt.MissingRequiredClaimError as e:
                return jsonify({"error": f"Token missing required claim: {e}"}), 401
            except jwt.InvalidTokenError:
                return jsonify({"error": "Invalid token"}), 401

            # Store the authenticated user info in Flask's g object
            g.current_user = {
                "user_id": payload["sub"],
                "username": payload["username"],
            }

            return f(*args, **kwargs)

        return decorated

    # Make the decorator accessible on the app for external use
    app.token_required = token_required

    # --- Routes ---

    @app.route("/auth/register", methods=["POST"])
    def register():
        """Register a new user."""
        data = request.get_json()

        if not data:
            return jsonify({"error": "Request body must be JSON"}), 400

        username = data.get("username", "").strip()
        password = data.get("password", "")

        if not username or not password:
            return jsonify({"error": "Username and password are required"}), 400

        if len(password) < 8:
            return jsonify({"error": "Password must be at least 8 characters"}), 400

        if username in users_db:
            return jsonify({"error": "Username already exists"}), 409

        user_id = str(len(users_db) + 1)
        users_db[username] = {
            "user_id": user_id,
            "username": username,
            "password_hash": generate_password_hash(password),
        }

        return jsonify({
            "message": "User registered successfully",
            "user_id": user_id,
            "username": username,
        }), 201

    @app.route("/auth/login", methods=["POST"])
    def login():
        """Authenticate user and return a JWT token."""
        data = request.get_json()

        if not data:
            return jsonify({"error": "Request body must be JSON"}), 400

        username = data.get("username", "").strip()
        password = data.get("password", "")

        if not username or not password:
            return jsonify({"error": "Username and password are required"}), 400

        user = users_db.get(username)

        # Use constant-time comparison via check_password_hash to prevent timing attacks
        if not user or not check_password_hash(user["password_hash"], password):
            return jsonify({"error": "Invalid username or password"}), 401

        token = generate_token(user["user_id"], user["username"])

        return jsonify({
            "message": "Login successful",
            "access_token": token,
            "token_type": "Bearer",
            "expires_in_minutes": app.config["JWT_ACCESS_TOKEN_EXPIRES_MINUTES"],
        }), 200

    @app.route("/auth/verify", methods=["GET"])
    @token_required
    def verify_token():
        """Verify that the current token is valid. Protected endpoint."""
        return jsonify({
            "message": "Token is valid",
            "user": g.current_user,
        }), 200

    @app.route("/protected", methods=["GET"])
    @token_required
    def protected_resource():
        """Example protected endpoint."""
        return jsonify({
            "message": f"Hello, {g.current_user['username']}! This is a protected resource.",
            "user": g.current_user,
        }), 200

    @app.route("/health", methods=["GET"])
    def health_check():
        """Public health check endpoint."""
        return jsonify({"status": "healthy"}), 200

    return app


